import React, { useState } from 'react';
import { ScaleIcon } from './IconComponents';

type Language = 'ku' | 'ar' | 'en';

interface HeaderProps {
  language: Language;
  setLanguage: (lang: Language) => void;
}

const languageOptions: { key: Language; label: string; flag: string }[] = [
  { key: 'ku', label: 'کوردی', flag: '☀️' },
  { key: 'ar', label: 'عربي', flag: '🇸🇦' },
  { key: 'en', label: 'English', flag: '🇬🇧' },
];

const Header: React.FC<HeaderProps> = ({ language, setLanguage }) => {
  const [isOpen, setIsOpen] = useState(false);

  const selectedLanguage = languageOptions.find(opt => opt.key === language);

  return (
    <header className="sticky top-0 z-50 bg-slate-900/70 backdrop-blur-lg border-b border-slate-700">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <div className="flex items-center">
            <ScaleIcon className="h-8 w-8 text-amber-400" />
            <span className="font-bold text-xl ml-3 text-white">سیستەمی کەیسەکان</span>
          </div>
          <div className="relative">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="flex items-center justify-center w-32 px-4 py-2 text-sm font-medium text-white bg-slate-800 border border-slate-700 rounded-md hover:bg-slate-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 focus:ring-amber-400"
            >
              <span className="mr-2">{selectedLanguage?.flag}</span>
              <span>{selectedLanguage?.label}</span>
              <svg className={`ml-2 h-5 w-5 transform transition-transform ${isOpen ? '-rotate-180' : 'rotate-0'}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
            {isOpen && (
              <div className="absolute left-0 mt-2 w-32 rounded-md shadow-lg bg-slate-800 ring-1 ring-black ring-opacity-5">
                <div className="py-1" role="menu" aria-orientation="vertical" aria-labelledby="options-menu">
                  {languageOptions.map(option => (
                    <button
                      key={option.key}
                      onClick={() => {
                        setLanguage(option.key);
                        setIsOpen(false);
                      }}
                      className="flex items-center w-full px-4 py-2 text-sm text-gray-200 hover:bg-slate-700 hover:text-amber-300"
                      role="menuitem"
                    >
                       <span className="mr-2">{option.flag}</span>
                       <span>{option.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;

