import React, { useEffect, useRef } from 'react';
import { HomeIcon, BriefcaseIcon, UsersIcon, DollarSignIcon, FolderIcon, ChartBarIcon, SettingsIcon, ScaleIcon } from '../IconComponents';

interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
}

const NavLink: React.FC<{ icon: React.ReactNode; label: string; active?: boolean }> = ({ icon, label, active }) => (
  <a href="#" className={`flex items-center p-3 my-1 rounded-lg transition-colors duration-200 ${active ? 'bg-amber-500 text-slate-900 font-bold' : 'text-gray-300 hover:bg-slate-700 hover:text-white'}`}>
    {icon}
    <span className="mr-4">{label}</span>
  </a>
);

const Sidebar: React.FC<SidebarProps> = ({ sidebarOpen, setSidebarOpen }) => {
  const sidebar = useRef<HTMLDivElement>(null);

  // close on click outside
  useEffect(() => {
    const clickHandler = ({ target }: MouseEvent) => {
      if (!sidebar.current || !sidebarOpen) return;
      if (!sidebar.current.contains(target as Node)) {
        setSidebarOpen(false);
      }
    };
    document.addEventListener('click', clickHandler);
    return () => document.removeEventListener('click', clickHandler);
  });

  // close if the esc key is pressed
  useEffect(() => {
    const keyHandler = ({ keyCode }: KeyboardEvent) => {
      if (!sidebarOpen || keyCode !== 27) return;
      setSidebarOpen(false);
    };
    document.addEventListener('keydown', keyHandler);
    return () => document.removeEventListener('keydown', keyHandler);
  });


  return (
    <>
      {/* Sidebar backdrop (mobile) */}
      <div className={`fixed inset-0 bg-slate-900 bg-opacity-30 z-40 lg:hidden lg:z-auto transition-opacity duration-200 ${sidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} aria-hidden="true"></div>

      <div
        ref={sidebar}
        className={`flex flex-col absolute z-40 left-0 top-0 lg:static lg:left-auto lg:top-auto lg:translate-x-0 h-screen overflow-y-auto w-64 lg:w-72 lg:sidebar-expanded:!w-72 2xl:!w-72 shrink-0 bg-slate-900 border-l border-slate-700 p-4 transition-all duration-200 ease-in-out ${sidebarOpen ? 'translate-x-0' : '-translate-x-64'}`}
      >
        {/* Sidebar header */}
        <div className="flex justify-between mb-10 pr-3 sm:pr-2">
           <div className="flex items-center">
            <ScaleIcon className="h-8 w-8 text-amber-400" />
            <span className="font-bold text-xl ml-3 text-white">سیستەمی کەیسەکان</span>
          </div>
        </div>

        {/* Links */}
        <nav className="flex-grow">
          <NavLink icon={<HomeIcon className="w-6 h-6"/>} label="داشبۆرد" active />
          <NavLink icon={<BriefcaseIcon className="w-6 h-6"/>} label="کەیسەکان" />
          <NavLink icon={<UsersIcon className="w-6 h-6"/>} label="موکیلەکان" />
          <NavLink icon={<DollarSignIcon className="w-6 h-6"/>} label="دارایی" />
          <NavLink icon={<FolderIcon className="w-6 h-6"/>} label="ئەرشیف" />
          <NavLink icon={<ChartBarIcon className="w-6 h-6"/>} label="ڕاپۆرتەکان" />
        </nav>

        {/* Settings Link */}
        <div className="pt-4 border-t border-slate-700">
          <NavLink icon={<SettingsIcon className="w-6 h-6"/>} label="ڕێکخستنەکان" />
        </div>
      </div>
    </>
  );
};

