interface StatCardProps {
    icon: React.ReactNode;
    title: string;
    value: string;
    change: string;
    changeType: 'increase' | 'decrease' | 'neutral';
}

const StatCard: React.FC<StatCardProps> = ({ icon, title, value, change, changeType }) => {
    const changeColor = {
        increase: 'text-green-500',
        decrease: 'text-red-500',
        neutral: 'text-gray-500',
    };

    return (
        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700 flex items-start justify-between">
            <div>
                <div className="flex items-center text-gray-400 mb-2">
                    {icon}
                    <h3 className="mr-2 text-sm font-medium uppercase tracking-wider">{title}</h3>
                </div>
                <p className="text-3xl font-bold text-white">{value}</p>
            </div>
            <div className={`inline-flex items-center text-sm font-semibold px-2 py-1 rounded-full ${changeColor[changeType]}`}>
               {changeType === 'increase' && '▲'}
               {changeType === 'decrease' && '▼'}
               <span className="mr-1">{change}</span>
            </div>
        </div>
    );
};

