import React, { useState } from 'react';
import Sidebar from './dashboard/Sidebar';
import DashboardHeader from './dashboard/DashboardHeader';
import DashboardHome from './dashboard/DashboardHome';
import CasesPage from './dashboard/pages/CasesPage';
import ClientsPage from './dashboard/pages/ClientsPage';
import FinancePage from './dashboard/pages/FinancePage';
import ArchivePage from './dashboard/pages/ArchivePage';
import ReportsPage from './dashboard/pages/ReportsPage';
import SettingsPage from './dashboard/pages/SettingsPage';
import CalendarPage from './dashboard/pages/CalendarPage';
import NotesPage from './dashboard/pages/NotesPage';

export type Page = 'dashboard' | 'cases' | 'clients' | 'finance' | 'archive' | 'reports' | 'calendar' | 'settings' | 'notes';
export type UserRole = 'Lawyer' | 'Secretariat';

interface DashboardProps {
  setShowDashboard: (show: boolean) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ setShowDashboard }) => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activePage, setActivePage] = useState<Page>('dashboard');
  const [userRole, setUserRole] = useState<UserRole>('Lawyer');

  const renderPage = () => {
    switch (activePage) {
      case 'dashboard': return <DashboardHome />;
      case 'cases': return <CasesPage />;
      case 'clients': return <ClientsPage userRole={userRole} />;
      case 'finance': return <FinancePage />;
      case 'archive': return <ArchivePage />;
      case 'reports': return <ReportsPage />;
      case 'calendar': return <CalendarPage />;
      case 'settings': return <SettingsPage />;
      case 'notes': return <NotesPage />;
      default: return <DashboardHome />;
    }
  };

  return (
    <div className="relative flex h-screen bg-slate-900 text-gray-300 overflow-hidden font-sans">
      <Sidebar 
        sidebarOpen={sidebarOpen} 
        setSidebarOpen={setSidebarOpen} 
        activePage={activePage}
        setActivePage={setActivePage}
      />

      <div className="relative flex flex-col flex-1 overflow-y-auto overflow-x-hidden">
        <DashboardHeader 
          sidebarOpen={sidebarOpen} 
          setSidebarOpen={setSidebarOpen} 
          handleLogout={() => setShowDashboard(false)}
          userRole={userRole}
          setUserRole={setUserRole}
        />

        <main>
          <div className="p-4 sm:p-6 lg:p-8 w-full max-w-7xl mx-auto">
            {renderPage()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useRef } from 'react';
import { HomeIcon, BriefcaseIcon, UsersIcon, DollarSignIcon, FolderIcon, ChartBarIcon, SettingsIcon, ScaleIcon, CalendarIcon, FileTextIcon } from '../IconComponents';
import type { Page } from '../Dashboard';

interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
  activePage: Page;
  setActivePage: (page: Page) => void;
}

const NavLink: React.FC<{ icon: React.ReactNode; label: string; active?: boolean; onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`flex items-center w-full p-3 my-1 rounded-lg transition-colors duration-200 ${active ? 'bg-amber-500 text-slate-900 font-bold' : 'text-gray-300 hover:bg-slate-700 hover:text-white'}`}>
    {icon}
    <span className="mr-4">{label}</span>
  </button>
);

const Sidebar: React.FC<SidebarProps> = ({ sidebarOpen, setSidebarOpen, activePage, setActivePage }) => {
  const sidebar = useRef<HTMLDivElement>(null);

  const handleLinkClick = (page: Page) => {
    setActivePage(page);
    if (sidebarOpen) {
      setSidebarOpen(false);
    }
  };

  // close on click outside
  useEffect(() => {
    const clickHandler = ({ target }: MouseEvent) => {
      if (!sidebar.current || !sidebarOpen) return;
      if (!sidebar.current.contains(target as Node)) {
        setSidebarOpen(false);
      }
    };
    document.addEventListener('click', clickHandler);
    return () => document.removeEventListener('click', clickHandler);
  });

  // close if the esc key is pressed
  useEffect(() => {
    const keyHandler = ({ keyCode }: KeyboardEvent) => {
      if (!sidebarOpen || keyCode !== 27) return;
      setSidebarOpen(false);
    };
    document.addEventListener('keydown', keyHandler);
    return () => document.removeEventListener('keydown', keyHandler);
  });


  return (
    <>
      {/* Sidebar backdrop (mobile) */}
      <div className={`fixed inset-0 bg-slate-900 bg-opacity-30 z-40 lg:hidden lg:z-auto transition-opacity duration-200 ${sidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} aria-hidden="true"></div>

      <div
        ref={sidebar}
        className={`flex flex-col absolute z-40 left-0 top-0 lg:static lg:left-auto lg:top-auto lg:translate-x-0 h-screen overflow-y-auto w-64 lg:w-72 lg:sidebar-expanded:!w-72 2xl:!w-72 shrink-0 bg-slate-900 border-l border-slate-700 p-4 transition-all duration-200 ease-in-out ${sidebarOpen ? 'translate-x-0' : '-translate-x-64'}`}
      >
        {/* Sidebar header */}
        <div className="flex justify-between mb-10 pr-3 sm:pr-2">
           <div className="flex items-center">
            <ScaleIcon className="h-8 w-8 text-amber-400" />
            <span className="font-bold text-xl ml-3 text-white">سیستەمی کەیسەکان</span>
          </div>
        </div>

        {/* Links */}
        <nav className="flex-grow">
          <NavLink icon={<HomeIcon className="w-6 h-6"/>} label="داشبۆرد" active={activePage === 'dashboard'} onClick={() => handleLinkClick('dashboard')} />
          <NavLink icon={<BriefcaseIcon className="w-6 h-6"/>} label="کەیسەکان" active={activePage === 'cases'} onClick={() => handleLinkClick('cases')} />
          <NavLink icon={<UsersIcon className="w-6 h-6"/>} label="موکیلەکان" active={activePage === 'clients'} onClick={() => handleLinkClick('clients')} />
          <NavLink icon={<DollarSignIcon className="w-6 h-6"/>} label="دارایی" active={activePage === 'finance'} onClick={() => handleLinkClick('finance')} />
          <NavLink icon={<CalendarIcon className="w-6 h-6"/>} label="ساڵنامە" active={activePage === 'calendar'} onClick={() => handleLinkClick('calendar')} />
          <NavLink icon={<FileTextIcon className="w-6 h-6"/>} label="تێبینییەکان" active={activePage === 'notes'} onClick={() => handleLinkClick('notes')} />
          <NavLink icon={<FolderIcon className="w-6 h-6"/>} label="ئەرشیف" active={activePage === 'archive'} onClick={() => handleLinkClick('archive')} />
          <NavLink icon={<ChartBarIcon className="w-6 h-6"/>} label="ڕاپۆرتەکان" active={activePage === 'reports'} onClick={() => handleLinkClick('reports')} />
        </nav>

        {/* Settings Link */}
        <div className="pt-4 border-t border-slate-700">
          <NavLink icon={<SettingsIcon className="w-6 h-6"/>} label="ڕێکخستنەکان" active={activePage === 'settings'} onClick={() => handleLinkClick('settings')} />
        </div>
      </div>
    </>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { MenuIcon, SearchIcon, BellIcon, LogOutIcon, SettingsIcon, UsersIcon } from '../IconComponents';
import type { UserRole } from '../Dashboard';

interface DashboardHeaderProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
  handleLogout: () => void;
  userRole: UserRole;
  setUserRole: (role: UserRole) => void;
}

const Dropdown: React.FC<{ align?: 'left' | 'right'; children: React.ReactNode; trigger: React.ReactNode }> = ({ children, trigger, align = 'right' }) => {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdown = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    const clickHandler = ({ target }: MouseEvent) => {
      if (!dropdown.current) return;
      if (!dropdownOpen || dropdown.current.contains(target as Node) || triggerRef.current?.contains(target as Node)) return;
      setDropdownOpen(false);
    };
    document.addEventListener('click', clickHandler);
    return () => document.removeEventListener('click', clickHandler);
  });

  return (
    <div className="relative inline-flex">
      <button ref={triggerRef} onClick={() => setDropdownOpen(!dropdownOpen)}>{trigger}</button>
      <div className={`origin-top-right z-10 absolute top-full min-w-[12rem] bg-slate-800 border border-slate-700 rounded-lg shadow-lg overflow-hidden mt-1 ${align === 'right' ? 'right-0' : 'left-0'} ${dropdownOpen ? 'block' : 'hidden'}`} ref={dropdown}>
        {children}
      </div>
    </div>
  );
};


