import React, { useState, useEffect } from 'react';
import { PlusIcon, FilterIcon, SearchIcon, MoreVerticalIcon, EditIcon, TrashIcon, ClockIcon, PlayIcon, PauseIcon } from '../../IconComponents';
import Modal from '../shared/Modal';

type CaseStatus = 'چالاک' | 'چاوەڕوان' | 'داخراو';

interface Case {
  id: string;
  client: string;
  type: string;
  status: CaseStatus;
  updated: string;
  trackedTime: number; // in seconds
}

const initialCasesData: Case[] = [
  { id: 'C-0584', client: 'کۆمپانیای بازرگانیی هێمن', type: 'بازرگانی', status: 'داخراو', updated: '2024-05-20', trackedTime: 4500 },
  { id: 'C-0601', client: 'ئارام خالید', type: 'مەدەنی', status: 'چالاک', updated: '2024-07-28', trackedTime: 1200 },
  { id: 'C-0602', client: 'شیلان ئەحمەد', type: 'خێزانی', status: 'چاوەڕوان', updated: '2024-07-25', trackedTime: 0 },
  { id: 'C-0603', client: 'حکومەتی هەرێم', type: 'کارگێڕی', status: 'چالاک', updated: '2024-07-29', trackedTime: 86400 },
  { id: 'C-0605', client: 'ئاسۆ عەبدوڵا', type: 'تاوانی', status: 'داخراو', updated: '2024-06-15', trackedTime: 500 },
];

const formatDuration = (seconds: number) => {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = seconds % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
};

const CaseForm: React.FC<{ caseData?: Case | null; onSave: (data: Case) => void; onCancel: () => void }> = ({ caseData, onSave, onCancel }) => {
  const [formData, setFormData] = useState<Case>(caseData || { id: `C-0${Math.floor(Math.random() * 1000)}`, client: '', type: '', status: 'چالاک', updated: new Date().toISOString().split('T')[0], trackedTime: 0 });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  return (
    <form onSubmit={handleSubmit}>
       <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">ناسنامەی کەیس</label>
            <input type="text" name="id" value={formData.id} onChange={handleChange} className="w-full bg-slate-700 border border-slate-600 rounded-lg p-2 focus:outline-none focus:border-amber-400" readOnly/>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">موکیل</label>
            <input type="text" name="client" value={formData.client} onChange={handleChange} required className="w-full bg-slate-700 border border-slate-600 rounded-lg p-2 focus:outline-none focus:border-amber-400" />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">جۆری کەیس</label>
            <input type="text" name="type" value={formData.type} onChange={handleChange} required className="w-full bg-slate-700 border border-slate-600 rounded-lg p-2 focus:outline-none focus:border-amber-400" />
          </div>
           <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">بارودۆخ</label>
            <select name="status" value={formData.status} onChange={handleChange} className="w-full bg-slate-700 border border-slate-600 rounded-lg p-2 focus:outline-none focus:border-amber-400">
                <option value="چالاک">چالاک</option>
                <option value="چاوەڕوان">چاوەڕوان</option>
                <option value="داخراو">داخراو</option>
            </select>
          </div>
       </div>
       <div className="mt-6 flex justify-end gap-4">
        <button type="button" onClick={onCancel} className="bg-slate-600 text-white px-4 py-2 rounded-lg hover:bg-slate-500">لابردن</button>
        <button type="submit" className="bg-amber-500 text-slate-900 font-bold px-4 py-2 rounded-lg hover:bg-amber-400">پاشەکەوت</button>
       </div>
    </form>
  )
}

const CasesPage: React.FC = () => {
  const [cases, setCases] = useState(initialCasesData);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isTimeModalOpen, setIsTimeModalOpen] = useState(false);
  const [editingCase, setEditingCase] = useState<Case | null>(null);
  const [activeTimerCaseId, setActiveTimerCaseId] = useState<string | null>(null);
  const [manualTime, setManualTime] = useState({ hours: 0, mins: 0 });

  useEffect(() => {
    let interval: any;
    if (activeTimerCaseId) {
      interval = setInterval(() => {
        setCases(prev => prev.map(c => c.id === activeTimerCaseId ? { ...c, trackedTime: c.trackedTime + 1 } : c));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [activeTimerCaseId]);

  const handleAddCase = () => {
    setEditingCase(null);
    setIsModalOpen(true);
  };

  const handleEditCase = (caseItem: Case) => {
    setEditingCase(caseItem);
    setIsModalOpen(true);
  };

  const handleSaveCase = (caseData: Case) => {
    if (editingCase) {
      setCases(cases.map(c => c.id === caseData.id ? { ...caseData, updated: new Date().toISOString().split('T')[0] } : c));
    } else {
      setCases([caseData, ...cases]);
    }
    setIsModalOpen(false);
    setEditingCase(null);
  }

  const handleLogTime = () => {
    if (editingCase) {
        const extraSecs = (manualTime.hours * 3600) + (manualTime.mins * 60);
        setCases(prev => prev.map(c => c.id === editingCase.id ? { ...c, trackedTime: c.trackedTime + extraSecs } : c));
        setIsTimeModalOpen(false);
        setManualTime({ hours: 0, mins: 0 });
    }
  }

  return (
    <div>
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-4 mb-8">
        <h1 className="text-2xl md:text-3xl text-white font-bold">کەیسەکان</h1>
        <button onClick={handleAddCase} className="flex items-center bg-amber-500 text-slate-900 font-bold px-4 py-2 rounded-lg hover:bg-amber-400 transition-colors">
          <PlusIcon className="w-5 h-5 ml-2" />
          <span>زیادکردنی کەیس</span>
        </button>
      </div>

      {/* Filters and Search */}
      <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 mb-6 flex flex-wrap items-center gap-4">
        <div className="relative flex-grow">
          <SearchIcon className="absolute h-5 w-5 top-2.5 left-3 text-gray-500" />
          <input type="text" placeholder="گەڕان بەدوای کەیس..." className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 pl-10 pr-4 focus:outline-none focus:border-amber-400" />
        </div>
      </div>

      {/* Cases Table */}
      <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-x-auto">
        <table className="w-full text-right">
          <thead className="border-b border-slate-700 text-sm text-gray-400 uppercase">
            <tr>
              <th className="p-4">کەیس</th>
              <th className="p-4">موکیل</th>
              <th className="p-4">بارودۆخ</th>
              <th className="p-4">کاتی تۆمارکراو</th>
              <th className="p-4 text-center">کردارەکان</th>
            </tr>
          </thead>
          <tbody>
            {cases.map((caseItem) => (
              <tr key={caseItem.id} className="border-b border-slate-700 hover:bg-slate-800/50">
                <td className="p-4">
                    <p className="font-mono text-amber-400">{caseItem.id}</p>
                    <p className="text-xs text-gray-500">{caseItem.type}</p>
                </td>
                <td className="p-4">{caseItem.client}</td>
                <td className="p-4">
                  <span className={`px-2 py-1 text-xs font-semibold rounded-full ${caseItem.status === 'چالاک' ? 'bg-green-500/20 text-green-400' : 'bg-gray-500/20 text-gray-400'}`}>
                    {caseItem.status}
                  </span>
                </td>
                <td className="p-4">
                    <div className="flex items-center gap-2">
                        <span className={`font-mono ${activeTimerCaseId === caseItem.id ? 'text-amber-400 animate-pulse' : 'text-gray-300'}`}>
                            {formatDuration(caseItem.trackedTime)}
                        </span>
                        <button 
                            onClick={() => setActiveTimerCaseId(activeTimerCaseId === caseItem.id ? null : caseItem.id)}
                            className={`p-1 rounded-full ${activeTimerCaseId === caseItem.id ? 'bg-red-500/20 text-red-500' : 'bg-green-500/20 text-green-500'}`}
                        >
                            {activeTimerCaseId === caseItem.id ? <PauseIcon className="w-4 h-4"/> : <PlayIcon className="w-4 h-4"/>}
                        </button>
                    </div>
                </td>
                <td className="p-4 text-center">
                   <div className="flex items-center justify-center gap-2">
                      <button onClick={() => { setEditingCase(caseItem); setIsTimeModalOpen(true); }} className="text-gray-400 hover:text-amber-400" title="تۆمارکردنی کاتی دەستی">
                        <ClockIcon className="w-5 h-5" />
                      </button>
                      <button onClick={() => handleEditCase(caseItem)} className="text-gray-400 hover:text-white">
                        <EditIcon className="w-5 h-5" />
                      </button>
                      <button className="text-gray-400 hover:text-red-400">
                        <TrashIcon className="w-5 h-5" />
                      </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingCase ? "دەستکاریکردنی کەیس" : "زیادکردنی کەیسی نوێ"}>
        <CaseForm caseData={editingCase} onSave={handleSaveCase} onCancel={() => setIsModalOpen(false)} />
      </Modal>

      <Modal isOpen={isTimeModalOpen} onClose={() => setIsTimeModalOpen(false)} title="تۆمارکردنی کاتی دەستی">
        <div className="space-y-4">
            <p className="text-gray-300">تۆمارکردنی کات بۆ کەیسی: <span className="text-amber-400 font-bold">{editingCase?.id}</span></p>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs text-gray-500 mb-1">کاتژمێر</label>
                    <input type="number" value={manualTime.hours} onChange={(e)=>setManualTime({...manualTime, hours: parseInt(e.target.value)||0})} className="w-full bg-slate-700 border border-slate-600 rounded p-2" />
                </div>
                <div>
                    <label className="block text-xs text-gray-500 mb-1">خولەک</label>
                    <input type="number" value={manualTime.mins} onChange={(e)=>setManualTime({...manualTime, mins: parseInt(e.target.value)||0})} className="w-full bg-slate-700 border border-slate-600 rounded p-2" />
                </div>
            </div>
            <button onClick={handleLogTime} className="w-full bg-amber-500 text-slate-900 font-bold py-2 rounded-lg mt-4">زیادکردن</button>
        </div>
      </Modal>
    </div>
  );
};

