const NotesPage: React.FC = () => {
  const [notes, setNotes] = useState(initialNotes);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(initialNotes[0].id);
  const [editingContent, setEditingContent] = useState(initialNotes[0].content);
  const [editingTitle, setEditingTitle] = useState(initialNotes[0].title);

  const activeNote = notes.find(n => n.id === selectedNoteId);

  const handleSelectNote = (note: Note) => {
    setSelectedNoteId(note.id);
    setEditingContent(note.content);
    setEditingTitle(note.title);
  };

  const handleNewNote = () => {
    const newNote = { id: Date.now().toString(), title: 'تێبینی نوێ', content: '', updated: new Date().toISOString().split('T')[0] };
    setNotes([newNote, ...notes]);
    handleSelectNote(newNote);
  };

  const handleSave = () => {
    if (selectedNoteId) {
      setNotes(notes.map(n => n.id === selectedNoteId ? { ...n, title: editingTitle, content: editingContent, updated: new Date().toISOString().split('T')[0] } : n));
    }
  };

  const handleDelete = (id: string) => {
    setNotes(notes.filter(n => n.id !== id));
    if (selectedNoteId === id) setSelectedNoteId(null);
  };

  return (
    <div className="h-[calc(100vh-140px)] flex bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
      {/* List Sidebar */}
      <div className="w-64 sm:w-80 border-l border-slate-700 flex flex-col">
        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-900/30">
          <h2 className="font-bold text-white">تێبینییەکان</h2>
          <button onClick={handleNewNote} className="p-2 bg-amber-500 text-slate-900 rounded-lg hover:bg-amber-400">
            <PlusIcon className="w-4 h-4" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto">
          {notes.map(note => (
            <button 
                key={note.id} 
                onClick={() => handleSelectNote(note)}
                className={`w-full text-right p-4 border-b border-slate-700/50 hover:bg-slate-700 transition-colors ${selectedNoteId === note.id ? 'bg-slate-700 border-r-4 border-amber-500' : ''}`}
            >
              <h3 className="font-bold text-white truncate">{note.title}</h3>
              <p className="text-xs text-gray-500 mt-1">{note.updated}</p>
              <p className="text-sm text-gray-400 mt-2 truncate opacity-70">{note.content || 'بەتاڵ...'}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Editor Main */}
      <div className="flex-1 flex flex-col">
        {selectedNoteId ? (
          <>
            <div className="p-4 border-b border-slate-700 flex justify-between items-center">
              <input 
                value={editingTitle} 
                onChange={(e) => setEditingTitle(e.target.value)}
                className="bg-transparent border-none text-xl font-bold text-white focus:outline-none flex-1"
                placeholder="ناونیشان..."
              />
              <div className="flex items-center gap-2">
                <button onClick={handleSave} className="p-2 text-gray-400 hover:text-amber-400" title="پاشەکەوت">
                  <SaveIcon className="w-6 h-6" />
                </button>
                <button onClick={() => handleDelete(selectedNoteId)} className="p-2 text-gray-400 hover:text-red-500" title="سڕینەوە">
                  <TrashIcon className="w-6 h-6" />
                </button>
              </div>
            </div>
            <div className="p-4 bg-slate-900/20 flex gap-2 border-b border-slate-700">
                <button className="px-2 py-1 text-xs bg-slate-700 rounded text-gray-300 hover:bg-slate-600 font-bold">B</button>
                <button className="px-2 py-1 text-xs bg-slate-700 rounded text-gray-300 hover:bg-slate-600 italic">I</button>
                <button className="flex items-center gap-1 px-2 py-1 text-xs bg-slate-700 rounded text-gray-300 hover:bg-slate-600">
                    <CheckSquareIcon className="w-3 h-3" /> لیستی کارەکان
                </button>
            </div>
            <textarea 
              value={editingContent} 
              onChange={(e) => setEditingContent(e.target.value)}
              className="flex-1 p-6 bg-transparent border-none text-gray-300 focus:outline-none resize-none leading-relaxed"
              placeholder="دەست بکە بە نووسین..."
            />
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-gray-500">
            <FileTextIcon className="w-16 h-16 opacity-10 mb-4" />
            <p>تێبینییەک هەڵبژێرە بۆ بینین یان تێبینی نوێ دروست بکە</p>
          </div>
        )}
      </div>
    </div>
  );
};

