import React, { useState } from 'react';
import Sidebar from './dashboard/Sidebar';
import DashboardHeader from './dashboard/DashboardHeader';
import DashboardHome from './dashboard/DashboardHome';
import CasesPage from './dashboard/pages/CasesPage';
import ClientsPage from './dashboard/pages/ClientsPage';
import FinancePage from './dashboard/pages/FinancePage';
import ArchivePage from './dashboard/pages/ArchivePage';
import ReportsPage from './dashboard/pages/ReportsPage';
import SettingsPage from './dashboard/pages/SettingsPage';
import CalendarPage from './dashboard/pages/CalendarPage';
import NotesPage from './dashboard/pages/NotesPage';
import TasksPage from './dashboard/pages/TasksPage';
import TeamPage from './dashboard/pages/TeamPage';

export type Page = 'dashboard' | 'cases' | 'clients' | 'finance' | 'archive' | 'reports' | 'calendar' | 'settings' | 'notes' | 'tasks' | 'team';
export type UserRole = 'Lawyer' | 'Secretariat';

interface DashboardProps {
  setShowDashboard: (show: boolean) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ setShowDashboard }) => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activePage, setActivePage] = useState<Page>('dashboard');
  const [userRole, setUserRole] = useState<UserRole>('Lawyer');

  const renderPage = () => {
    switch (activePage) {
      case 'dashboard': return <DashboardHome setActivePage={setActivePage} />;
      case 'cases': return <CasesPage />;
      case 'clients': return <ClientsPage userRole={userRole} />;
      case 'finance': return <FinancePage />;
      case 'archive': return <ArchivePage userRole={userRole} />;
      case 'reports': return <ReportsPage />;
      case 'calendar': return <CalendarPage />;
      case 'settings': return <SettingsPage />;
      case 'notes': return <NotesPage />;
      case 'tasks': return <TasksPage />;
      case 'team': return <TeamPage />;
      default: return <DashboardHome setActivePage={setActivePage} />;
    }
  };

  return (
    <div className="relative flex h-screen bg-slate-900 text-gray-300 overflow-hidden font-sans">
      <Sidebar 
        sidebarOpen={sidebarOpen} 
        setSidebarOpen={setSidebarOpen} 
        activePage={activePage}
        setActivePage={setActivePage}
      />

      <div className="relative flex flex-col flex-1 overflow-y-auto overflow-x-hidden">
        <DashboardHeader 
          sidebarOpen={sidebarOpen} 
          setSidebarOpen={setSidebarOpen} 
          handleLogout={() => setShowDashboard(false)}
          userRole={userRole}
          setUserRole={setUserRole}
        />

        <main>
          <div className="p-4 sm:p-6 lg:p-8 w-full max-w-7xl mx-auto">
            {renderPage()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useRef } from 'react';
import { 
  HomeIcon, 
  BriefcaseIcon, 
  UsersIcon, 
  DollarSignIcon, 
  FolderIcon, 
  ChartBarIcon, 
  SettingsIcon, 
  ScaleIcon, 
  CalendarIcon, 
  FileTextIcon,
  CheckSquareIcon
} from '../IconComponents';
import type { Page } from '../Dashboard';

interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
  activePage: Page;
  setActivePage: (page: Page) => void;
}

const NavLink: React.FC<{ icon: React.ReactNode; label: string; active?: boolean; onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`flex items-center w-full p-3 my-1 rounded-xl transition-all duration-200 ${active ? 'bg-amber-500 text-slate-900 font-bold shadow-lg shadow-amber-500/20' : 'text-gray-400 hover:bg-slate-800 hover:text-white'}`}>
    <span className={`${active ? 'text-slate-900' : ''}`}>{icon}</span>
    <span className="mr-4 text-sm font-bold">{label}</span>
  </button>
);

const Sidebar: React.FC<SidebarProps> = ({ sidebarOpen, setSidebarOpen, activePage, setActivePage }) => {
  const sidebar = useRef<HTMLDivElement>(null);

  const handleLinkClick = (page: Page) => {
    setActivePage(page);
    if (sidebarOpen) {
      setSidebarOpen(false);
    }
  };

  useEffect(() => {
    const clickHandler = ({ target }: MouseEvent) => {
      if (!sidebar.current || !sidebarOpen) return;
      if (!sidebar.current.contains(target as Node)) {
        setSidebarOpen(false);
      }
    };
    document.addEventListener('click', clickHandler);
    return () => document.removeEventListener('click', clickHandler);
  });

  useEffect(() => {
    const keyHandler = ({ keyCode }: KeyboardEvent) => {
      if (!sidebarOpen || keyCode !== 27) return;
      setSidebarOpen(false);
    };
    document.addEventListener('keydown', keyHandler);
    return () => document.removeEventListener('keydown', keyHandler);
  });


  return (
    <>
      <div className={`fixed inset-0 bg-slate-900 bg-opacity-30 z-40 lg:hidden lg:z-auto transition-opacity duration-200 ${sidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} aria-hidden="true"></div>

      <div
        ref={sidebar}
        className={`flex flex-col absolute z-40 left-0 top-0 lg:static lg:left-auto lg:top-auto lg:translate-x-0 h-screen overflow-y-auto w-64 lg:w-72 shrink-0 bg-slate-900 border-l border-slate-800 p-6 transition-all duration-300 ease-in-out ${sidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-64'}`}
      >
        <div className="flex items-center mb-10">
          <ScaleIcon className="h-9 w-9 text-amber-500" />
          <span className="font-bold text-xl ml-3 text-white tracking-tight">بەڕێوەبەری یاسایی</span>
        </div>

        <nav className="flex-grow space-y-1">
          <NavLink icon={<HomeIcon className="w-5 h-5"/>} label="داشبۆرد" active={activePage === 'dashboard'} onClick={() => handleLinkClick('dashboard')} />
          <NavLink icon={<BriefcaseIcon className="w-5 h-5"/>} label="کەیسەکان" active={activePage === 'cases'} onClick={() => handleLinkClick('cases')} />
          <NavLink icon={<UsersIcon className="w-5 h-5"/>} label="موکیلەکان" active={activePage === 'clients'} onClick={() => handleLinkClick('clients')} />
          <NavLink icon={<CheckSquareIcon className="w-5 h-5"/>} label="کارەکان" active={activePage === 'tasks'} onClick={() => handleLinkClick('tasks')} />
          <NavLink icon={<DollarSignIcon className="w-5 h-5"/>} label="دارایی" active={activePage === 'finance'} onClick={() => handleLinkClick('finance')} />
          <NavLink icon={<CalendarIcon className="w-5 h-5"/>} label="ساڵنامە" active={activePage === 'calendar'} onClick={() => handleLinkClick('calendar')} />
          <NavLink icon={<FileTextIcon className="w-5 h-5"/>} label="تێبینییەکان" active={activePage === 'notes'} onClick={() => handleLinkClick('notes')} />
          <NavLink icon={<FolderIcon className="w-5 h-5"/>} label="ئەرشیف" active={activePage === 'archive'} onClick={() => handleLinkClick('archive')} />

          <div className="pt-4 mt-4 border-t border-slate-800">
             <NavLink icon={<UsersIcon className="w-5 h-5"/>} label="تیمی نووسینگە" active={activePage === 'team'} onClick={() => handleLinkClick('team')} />
             <NavLink icon={<ChartBarIcon className="w-5 h-5"/>} label="ڕاپۆرتەکان" active={activePage === 'reports'} onClick={() => handleLinkClick('reports')} />
          </div>
        </nav>

        <div className="pt-6 border-t border-slate-800 mt-auto">
          <NavLink icon={<SettingsIcon className="w-5 h-5"/>} label="ڕێکخستنەکان" active={activePage === 'settings'} onClick={() => handleLinkClick('settings')} />
        </div>
      </div>
    </>
  );
};

export default Sidebar;

