  priority: 'High' | 'Medium' | 'Low';
  dueDate: string;
  assignee: string;
}

const initialTasks: Task[] = [
  { id: '1', title: 'ئامادەکردنی پەڕاوی کەیسی #C-0601', status: 'In Progress', priority: 'High', dueDate: '2024-08-05', assignee: 'ئارام' },
  { id: '2', title: 'پەیوەندی بە پزیشکی دادوەری', status: 'Todo', priority: 'Medium', dueDate: '2024-08-03', assignee: 'شیلان' },
  { id: '3', title: 'وەرگرتنی واژۆی موکیل', status: 'Done', priority: 'High', dueDate: '2024-07-30', assignee: 'ئارام' },
  { id: '4', title: 'کۆبوونەوە لەگەڵ تیمی یاسایی', status: 'Todo', priority: 'Low', dueDate: '2024-08-10', assignee: 'هەمووان' },
  { id: '5', title: 'ناردنی ڕاپۆرتی دارایی', status: 'In Progress', priority: 'Medium', dueDate: '2024-08-02', assignee: 'ئاسۆ' },
];

const TasksPage: React.FC = () => {
  const [tasks, setTasks] = useState(initialTasks);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const getPriorityColor = (p: string) => {
    switch(p) {
      case 'High': return 'text-red-500 bg-red-500/10 border-red-500/20';
      case 'Medium': return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
      case 'Low': return 'text-green-500 bg-green-500/10 border-green-500/20';
      default: return 'text-gray-500 bg-gray-500/10 border-gray-500/20';
    }
  };

  const filteredTasks = tasks.filter(t => t.title.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl text-white font-bold">کارەکان (Tasks)</h1>
          <p className="text-gray-400 mt-1">بەڕێوەبردنی ئەرک و کارەکانی نووسینگە.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-amber-500 text-slate-900 font-bold px-6 py-3 rounded-xl hover:bg-amber-400 transition-all shadow-xl shadow-amber-500/20 flex items-center"
        >
          <PlusIcon className="w-5 h-5 ml-2" />
          کاری نوێ
        </button>
      </div>

      <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex flex-wrap items-center gap-4">
        <div className="relative flex-grow min-w-[280px]">
          <SearchIcon className="absolute h-5 w-5 top-3 left-4 text-gray-500" />
          <input 
            type="text" 
            placeholder="گەڕان بەدوای کارەکان..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-900/80 border border-slate-700 rounded-xl py-3 pl-12 pr-5 focus:outline-none focus:border-amber-500 text-gray-200"
          />
        </div>
        <button className="p-3 bg-slate-900 border border-slate-700 text-gray-400 hover:text-white rounded-xl transition-all">
           <FilterIcon className="w-5 h-5" />
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {['Todo', 'In Progress', 'Done'].map(status => (
          <div key={status} className="space-y-4">
             <div className="flex items-center justify-between px-2">
                <h3 className="font-bold text-gray-400 uppercase tracking-widest text-xs">
                    {status === 'Todo' ? 'بۆ ئەنجامدان' : status === 'In Progress' ? 'لە پڕۆسێسدایە' : 'تەواوکراو'}
                </h3>
                <span className="bg-slate-800 text-gray-500 text-[10px] font-bold px-2 py-0.5 rounded-full border border-slate-700">
                    {filteredTasks.filter(t => t.status === status).length}
                </span>
             </div>

             <div className="space-y-4 min-h-[300px]">
                {filteredTasks.filter(t => t.status === status).map(task => (
                  <div key={task.id} className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-md hover:border-amber-500/30 transition-all group">
                     <div className="flex justify-between items-start mb-3">
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded border ${getPriorityColor(task.priority)}`}>
                            {task.priority}
                        </span>
                        <button className="text-gray-600 hover:text-white group-hover:opacity-100 opacity-0 transition-opacity">
                            <MoreVerticalIcon className="w-4 h-4" />
                        </button>
                     </div>
                     <h4 className="text-white font-bold mb-4 leading-relaxed">{task.title}</h4>
                     <div className="flex items-center justify-between border-t border-slate-700/50 pt-4">
                        <div className="flex items-center text-gray-500 text-xs font-bold">
                            <ClockIcon className="w-3 h-3 ml-1.5" />
                            {task.dueDate}
                        </div>
                        <div className="w-7 h-7 bg-slate-700 rounded-full flex items-center justify-center text-[10px] font-bold text-amber-500 border border-slate-600">
                            {task.assignee.charAt(0)}
                        </div>
                     </div>
                  </div>
                ))}
             </div>
          </div>
        ))}
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="زیادکردنی کاری نوێ">
          <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-2 uppercase">ناونیشانی کار</label>
                <input placeholder="چی پێویستە بکرێت؟" className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:border-amber-500 outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-xs font-bold text-gray-500 mb-2 uppercase">گرنگی (Priority)</label>
                   <select className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:border-amber-500 outline-none">
                      <option>High</option>
                      <option>Medium</option>
                      <option>Low</option>
                   </select>
                </div>
                <div>
                   <label className="block text-xs font-bold text-gray-500 mb-2 uppercase">کەسی بەرپرس</label>
                   <input placeholder="ناو..." className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:border-amber-500 outline-none" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-2 uppercase">بەرواری کۆتایی</label>
                <input type="date" className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:border-amber-500 outline-none" />
              </div>
              <button className="w-full bg-amber-500 text-slate-900 font-bold py-4 rounded-xl mt-4 shadow-lg shadow-amber-500/20 active:scale-95 transition-all">
                پاشەکەوتکردن
              </button>
          </div>
      </Modal>
    </div>
  );
};

