import React, { useState } from 'react';
import { ScaleIcon } from './IconComponents';

type Language = 'ku' | 'ar' | 'en';

interface HeaderProps {
  language: Language;
  setLanguage: (lang: Language) => void;
}

const languageOptions: { key: Language; label: string; flag: string }[] = [
  { key: 'ku', label: 'کوردی', flag: '☀️' },
  { key: 'ar', label: 'عربي', flag: '🇸🇦' },
  { key: 'en', label: 'English', flag: '🇬🇧' },
];

const Header: React.FC<HeaderProps> = ({ language, setLanguage }) => {
  const [isOpen, setIsOpen] = useState(false);

  const selectedLanguage = languageOptions.find(opt => opt.key === language);

  return (
    <header className="sticky top-0 z-50 bg-slate-900/60 backdrop-blur-xl border-b border-white/5 shadow-2xl">
      <div className="container mx-auto px-4 sm:px-6 lg:px-12">
        <div className="flex items-center justify-between h-20">
          <div className="flex items-center group cursor-pointer">
            <div className="relative">
                <div className="absolute inset-0 bg-amber-500 blur-lg opacity-20 group-hover:opacity-40 transition-opacity"></div>
                <ScaleIcon className="relative h-9 w-9 text-amber-500" />
            </div>
            <span className="font-bold text-2xl mr-4 text-white tracking-tight">بەڕێوەبەری یاسایی</span>
          </div>

          <div className="flex items-center gap-6">
            <nav className="hidden md:flex items-center gap-8 text-sm font-medium text-gray-400">
                <a href="#features" className="hover:text-amber-400 transition-colors">تایبەتمەندییەکان</a>
                <a href="#contact" className="hover:text-amber-400 transition-colors">پەیوەندی</a>
            </nav>

            <div className="relative">
                <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center justify-center min-w-[120px] px-4 py-2 text-sm font-bold text-white bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-all focus:outline-none focus:ring-2 focus:ring-amber-500/50"
                >
                <span className="ml-2">{selectedLanguage?.flag}</span>
                <span>{selectedLanguage?.label}</span>
                <svg className={`mr-2 h-4 w-4 transform transition-transform duration-300 ${isOpen ? '-rotate-180' : 'rotate-0'}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
                </button>
                {isOpen && (
                <div className="absolute left-0 mt-3 w-40 rounded-2xl shadow-2xl bg-slate-800 border border-white/10 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="py-1">
                    {languageOptions.map(option => (
                        <button
                        key={option.key}
                        onClick={() => {
                            setLanguage(option.key);
                            setIsOpen(false);
                        }}
                        className={`flex items-center w-full px-5 py-3 text-sm text-right ${language === option.key ? 'bg-amber-500/10 text-amber-400 font-bold' : 'text-gray-300 hover:bg-white/5 hover:text-white'}`}
                        >
                        <span className="ml-3 text-lg">{option.flag}</span>
                        <span>{option.label}</span>
                        </button>
                    ))}
                    </div>
                </div>
                )}
            </div>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;

