import React, { useState } from 'react';
import { 
  FolderIcon, 
  SearchIcon, 
  TrashIcon, 
  RefreshCwIcon,
  BriefcaseIcon,
  CheckCircleIcon,
  LockIcon
} from '../../IconComponents';
import { UserRole } from '../../Dashboard';

interface ClosedCase {
  id: string;
  client: string;
  type: string;
  closeDate: string;
  reason: string;
  financialStatus: 'Clear' | 'Pending';
}

const initialClosedCases: ClosedCase[] = [
  { id: 'C-0421', client: 'کاک هێمن عەزیز', type: 'مەدەنی', closeDate: '2023-11-12', reason: 'کۆتایی هاتنی دانیشتنەکان', financialStatus: 'Clear' },
  { id: 'C-0399', client: 'نەریمان جەلال', type: 'خێزانی', closeDate: '2023-09-05', reason: 'ڕێککەوتن', financialStatus: 'Clear' },
  { id: 'C-0512', client: 'کۆمپانیای ئاسۆ', type: 'بازرگانی', closeDate: '2024-02-28', reason: 'کشانەوەی موکیل', financialStatus: 'Pending' },
  { id: 'C-0210', client: 'شیرین ئەحمەد', type: 'تاوانی', closeDate: '2023-05-15', reason: 'بەرائەت', financialStatus: 'Clear' },
];

interface ArchivePageProps {
  userRole: UserRole;
}

const ArchivePage: React.FC<ArchivePageProps> = ({ userRole }) => {
  const [closedCases, setClosedCases] = useState<ClosedCase[]>(initialClosedCases);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredCases = closedCases.filter(c => 
    c.client.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleRestore = (id: string) => {
    if (confirm('ئایا دڵنیایت لە گەڕاندنەوەی ئەم کەیسە بۆ لیستی چالاکەکان؟')) {
      setClosedCases(closedCases.filter(c => c.id !== id));
      alert(`کەیسی ${id} گەڕێنرایەوە بۆ لیستی چالاک.`);
    }
  };

  const handlePermanentDelete = (id: string) => {
    if (userRole !== 'Lawyer') {
      alert('تەنها پارێزەر دەتوانێت کەیسەکان بە هەمیشەیی بسڕێتەوە.');
      return;
    }
    if (confirm('ئەم کردارە ناگەڕێتەوە! ئایا دڵنیایت لە سڕینەوەی هەمیشەیی ئەم کەیسە؟')) {
      setClosedCases(closedCases.filter(c => c.id !== id));
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl text-white font-bold tracking-tight">ئەرشیفی کەیسەکان</h1>
          <p className="text-gray-400 mt-1 font-medium">کەیسە کۆن و داخراوەکان لێرەدا دەهێڵرێنەوە بۆ ئاماژە پێدان لە داهاتوو.</p>
        </div>
        <div className="flex items-center gap-3 px-4 py-2 bg-slate-800 rounded-xl border border-slate-700">
          <FolderIcon className="w-5 h-5 text-amber-500" />
          <span className="text-white font-bold">{closedCases.length} کەیسی ئەرشیفکراو</span>
        </div>
      </div>

      <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700">
        <div className="relative">
          <SearchIcon className="absolute h-5 w-5 top-3 left-4 text-gray-500" />
          <input 
            type="text" 
            placeholder="گەڕان لەناو ئەرشیفدا..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-900/80 border border-slate-700 rounded-xl py-3 pl-12 pr-5 focus:outline-none focus:border-amber-500 text-gray-200"
          />
        </div>
      </div>

      <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden shadow-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-slate-900/80 border-b border-slate-700 text-gray-500 text-xs font-bold uppercase tracking-widest">
                <th className="p-5">کەیس</th>
                <th className="p-5">موکیل</th>
                <th className="p-5">بەرواری داخستن</th>
                <th className="p-5">هۆکاری داخستن</th>
                <th className="p-5">دارایی</th>
                <th className="p-5 text-center">کردارەکان</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-700/50">
              {filteredCases.map((c) => (
                <tr key={c.id} className="hover:bg-slate-700/40 transition-colors group">
                  <td className="p-5">
                    <div className="flex items-center">
                      <BriefcaseIcon className="w-5 h-5 text-slate-500 ml-3" />
                      <span className="text-amber-400 font-mono font-bold">{c.id}</span>
                    </div>
                  </td>
                  <td className="p-5 text-white font-medium">{c.client}</td>
                  <td className="p-5 text-gray-400">{c.closeDate}</td>
                  <td className="p-5 text-gray-500 text-sm">{c.reason}</td>
                  <td className="p-5">
                    <span className={`px-2 py-1 rounded-md text-[10px] font-bold ${c.financialStatus === 'Clear' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'bg-amber-500/10 text-amber-400 border border-amber-500/20'}`}>
                      {c.financialStatus === 'Clear' ? 'پاکتاو' : 'ماوە'}
                    </span>
                  </td>
                  <td className="p-5">
                    <div className="flex items-center justify-center gap-2">
                      <button 
                        onClick={() => handleRestore(c.id)}
                        className="p-2 text-gray-400 hover:text-green-500 hover:bg-slate-900 rounded-lg transition-all"
                        title="گەڕاندنەوە (Restore)"
                      >
                        <RefreshCwIcon className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => handlePermanentDelete(c.id)}
                        className={`p-2 text-gray-400 hover:text-red-500 hover:bg-slate-900 rounded-lg transition-all ${userRole !== 'Lawyer' ? 'cursor-not-allowed opacity-50' : ''}`}
                        title="سڕینەوەی هەمیشەیی"
                      >
                        <TrashIcon className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredCases.length === 0 && (
                <tr>
                  <td colSpan={6} className="p-20 text-center text-gray-500 italic">هیچ کەیسێک نەدۆزرایەوە.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ArchivePage;

import React, { useState } from 'react';
import { ChartBarIcon, FileTextIcon, DownloadIcon, CheckCircleIcon, DollarSignIcon, BriefcaseIcon } from '../../IconComponents';

const ReportsPage: React.FC = () => {
  const [reportType, setReportType] = useState('Case');
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  const handleGenerate = () => {
    setIsGenerating(true);
    setIsFinished(false);
    setProgress(0);

    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsGenerating(false);
          setIsFinished(true);
          return 100;
        }
        return prev + 10;
      });
    }, 300);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl text-white font-bold">ڕاپۆرتەکان</h1>
          <p className="text-gray-400 mt-1 font-medium">ئامادەکردنی ڕاپۆرتی ورد بۆ لایەنی دارایی و پڕۆسەی کەیسەکان.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Config Form */}
        <div className="lg:col-span-5 bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl h-fit">
          <h2 className="text-xl font-bold text-white mb-6">هەڵبژاردنی ڕاپۆرت</h2>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setReportType('Finance')}
