import React, { useState } from 'react';
import { PlusIcon, SaveIcon, TrashIcon, CheckSquareIcon, FileTextIcon } from '../../IconComponents';

interface Note {
  id: string;
  title: string;
  content: string;
  updated: string;
}

const initialNotes: Note[] = [
  { id: '1', title: 'ئەرکەکانی ئەمڕۆ', content: '- تەلەفۆن بۆ ئارام\n- ئامادەکردنی بەڵگەنامەی کەیسی #C-0601', updated: '2024-08-01' },
  { id: '2', title: 'بیرخستنەوەی کۆبوونەوە', content: 'کۆبوونەوە لەگەڵ پارێزەرانی تیمی بازرگانی لە کاتژمێر ٤', updated: '2024-07-30' },
];

const NotesPage: React.FC = () => {
  const [notes, setNotes] = useState(initialNotes);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(initialNotes[0].id);
  const [editingContent, setEditingContent] = useState(initialNotes[0].content);
  const [editingTitle, setEditingTitle] = useState(initialNotes[0].title);

  const activeNote = notes.find(n => n.id === selectedNoteId);

  const handleSelectNote = (note: Note) => {
    setSelectedNoteId(note.id);
    setEditingContent(note.content);
    setEditingTitle(note.title);
  };

  const handleNewNote = () => {
    const newNote = { id: Date.now().toString(), title: 'تێبینی نوێ', content: '', updated: new Date().toISOString().split('T')[0] };
    setNotes([newNote, ...notes]);
    handleSelectNote(newNote);
  };

  const handleSave = () => {
    if (selectedNoteId) {
      setNotes(notes.map(n => n.id === selectedNoteId ? { ...n, title: editingTitle, content: editingContent, updated: new Date().toISOString().split('T')[0] } : n));
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('ئایا دڵنیایت لە سڕینەوەی ئەم تێبینییە؟')) {
      setNotes(notes.filter(n => n.id !== id));
      if (selectedNoteId === id) setSelectedNoteId(null);
    }
  };

  const applyFormat = (tag: string) => {
    // This is a simplified simulation since we are using a textarea
    // In a real rich text editor, this would handle selection and DOM tags
    if (tag === 'bold') setEditingContent(prev => prev + ' **BOLD TEXT** ');
    if (tag === 'italic') setEditingContent(prev => prev + ' *ITALIC TEXT* ');
  };

  return (
    <div className="h-[calc(100vh-140px)] flex bg-slate-950 rounded-2xl border border-slate-700 overflow-hidden shadow-2xl animate-in fade-in duration-500">
      {/* List Sidebar */}
      <div className="w-64 sm:w-80 border-l border-slate-800 flex flex-col bg-slate-900">
        <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950/30">
          <h2 className="font-black text-white uppercase tracking-widest text-sm">تێبینییەکان</h2>
          <button onClick={handleNewNote} className="w-9 h-9 flex items-center justify-center bg-amber-500 text-slate-950 rounded-xl hover:bg-amber-400 transition-all shadow-lg shadow-amber-500/20 active:scale-90">
            <PlusIcon className="w-5 h-5" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto no-scrollbar">
          {notes.length > 0 ? notes.map(note => (
            <button 
                key={note.id} 
                onClick={() => handleSelectNote(note)}
                className={`w-full text-right p-5 border-b border-slate-800/50 hover:bg-slate-800/50 transition-all ${selectedNoteId === note.id ? 'bg-slate-800/80 border-r-4 border-amber-500' : ''}`}
            >
              <h3 className="font-bold text-white truncate text-lg">{note.title}</h3>
              <p className="text-[10px] text-gray-500 mt-1 font-black uppercase tracking-widest">{note.updated}</p>
              <p className="text-sm text-gray-500 mt-2 truncate font-medium opacity-60 leading-relaxed">{note.content || 'تێبینی بەتاڵ...'}</p>
            </button>
          )) : (
            <div className="p-10 text-center opacity-30">
               <FileTextIcon className="w-12 h-12 mx-auto mb-2" />
               <p className="text-xs">هیچ تێبینییەک نییە</p>
            </div>
          )}
        </div>
      </div>

      {/* Editor Main */}
      <div className="flex-1 flex flex-col bg-slate-900/40">
        {selectedNoteId ? (
          <>
            <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950/20">
              <input 
                value={editingTitle} 
                onChange={(e) => setEditingTitle(e.target.value)}
                className="bg-transparent border-none text-2xl font-black text-white focus:outline-none flex-1 tracking-tight"
                placeholder="ناونیشانی تێبینی..."
              />
              <div className="flex items-center gap-3">
                <button onClick={handleSave} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-amber-500 hover:bg-slate-800 rounded-xl transition-all" title="پاشەکەوت">
                  <SaveIcon className="w-6 h-6" />
                </button>
                <button onClick={() => handleDelete(selectedNoteId)} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-red-500 hover:bg-slate-800 rounded-xl transition-all" title="سڕینەوە">
                  <TrashIcon className="w-6 h-6" />
                </button>
              </div>
            </div>

            {/* Formatting Bar */}
            <div className="px-6 py-3 bg-slate-950/40 flex items-center gap-4 border-b border-slate-800">
                <div className="flex gap-2">
                  <button onClick={() => applyFormat('bold')} className="w-8 h-8 flex items-center justify-center text-sm font-black bg-slate-800 text-gray-300 rounded-lg hover:bg-slate-700 hover:text-white transition-all">B</button>
                  <button onClick={() => applyFormat('italic')} className="w-8 h-8 flex items-center justify-center text-sm italic bg-slate-800 text-gray-300 rounded-lg hover:bg-slate-700 hover:text-white transition-all">I</button>
                </div>
                <div className="h-6 w-px bg-slate-800"></div>
                <button className="flex items-center gap-2 px-3 py-1.5 text-xs font-bold bg-slate-800 text-gray-400 rounded-lg hover:bg-slate-700 hover:text-white transition-all">
                    <CheckSquareIcon className="w-4 h-4" /> لیست
                </button>
            </div>

            <textarea 
              value={editingContent} 
              onChange={(e) => setEditingContent(e.target.value)}
              className="flex-1 p-8 bg-transparent border-none text-gray-300 focus:outline-none resize-none leading-loose font-medium text-lg placeholder:text-slate-800"
              placeholder="دەست بکە بە نووسین لێرەوە..."
            />

            <div className="px-8 py-4 bg-slate-950/20 border-t border-slate-800 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.2em] text-gray-600">
               <span>کۆتا گۆڕانکاری: {activeNote?.updated}</span>
               <span>{editingContent.length} نووسە</span>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-800">
            <div className="w-24 h-24 rounded-full bg-slate-800/50 flex items-center justify-center mb-6 border border-slate-800">
              <FileTextIcon className="w-12 h-12 opacity-20" />
            </div>
            <p className="font-bold tracking-widest uppercase">تێبینییەک هەڵبژێرە بۆ دەستکاریکردن</p>
            <button onClick={handleNewNote} className="mt-8 text-amber-500 font-black text-xs uppercase tracking-widest hover:underline">یان تێبینی نوێ دروست بکە</button>
          </div>
        )}
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

