                        <input placeholder="0750..." className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white font-bold focus:border-amber-500 outline-none transition-all" />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-500 mb-2 uppercase tracking-widest">ئیمەیڵ</label>
                        <input type="email" placeholder="example@..." className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white font-bold focus:border-amber-500 outline-none transition-all" />
                      </div>
                  </div>
                  <div className="flex items-center gap-3 p-4 bg-slate-950 rounded-xl border border-slate-800">
                      <input type="checkbox" id="is-company" className="w-6 h-6 rounded-lg border-slate-800 text-amber-500 bg-slate-900 focus:ring-amber-500/30" />
                      <label htmlFor="is-company" className="text-sm font-bold text-gray-300">ئەم موکیلە "کۆمپانیا"یە</label>
                  </div>
              </div>
              <div className="pt-6 flex gap-4">
                <button onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700 transition-all">لابردن</button>
                <button className="flex-1 py-4 bg-amber-500 text-slate-950 font-black rounded-xl hover:bg-amber-400 transition-all shadow-xl shadow-amber-500/20 active:scale-95">پاشەکەوت</button>
              </div>
          </div>
      </Modal>
    </div>
  );
};

