import React, { useState } from 'react';
// Added RefreshCwIcon to the imports from IconComponents
import { ChartBarIcon, FileTextIcon, DownloadIcon, CheckCircleIcon, DollarSignIcon, BriefcaseIcon, RefreshCwIcon } from '../../IconComponents';

const ReportsPage: React.FC = () => {
  const [reportType, setReportType] = useState('Case');
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  const handleGenerate = () => {
    setIsGenerating(true);
    setIsFinished(false);
    setProgress(0);

    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsGenerating(false);
          setIsFinished(true);
          return 100;
        }
        return prev + 10;
      });
    }, 300);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl text-white font-bold">ڕاپۆرتەکان</h1>
          <p className="text-gray-400 mt-1 font-medium">ئامادەکردنی ڕاپۆرتی ورد بۆ لایەنی دارایی و پڕۆسەی کەیسەکان.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Config Form */}
        <div className="lg:col-span-5 bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl h-fit">
          <h2 className="text-xl font-bold text-white mb-6">هەڵبژاردنی ڕاپۆرت</h2>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setReportType('Finance')}
                className={`flex items-center justify-center gap-2 p-3 rounded-xl border font-bold transition-all ${reportType === 'Finance' ? 'bg-amber-500 text-slate-900 border-amber-500' : 'bg-slate-900 text-gray-400 border-slate-700 hover:bg-slate-800'}`}
              >
                <DollarSignIcon className="w-5 h-5" />
                دارایی
              </button>
              <button 
                onClick={() => setReportType('Case')}
                className={`flex items-center justify-center gap-2 p-3 rounded-xl border font-bold transition-all ${reportType === 'Case' ? 'bg-amber-500 text-slate-900 border-amber-500' : 'bg-slate-900 text-gray-400 border-slate-700 hover:bg-slate-800'}`}
              >
                <BriefcaseIcon className="w-5 h-5" />
                کەیسەکان
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-400 mb-2">دیاریکردنی مەودا</label>
                <select className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:ring-1 focus:ring-amber-500">
                  <option>ئەم مانگە</option>
                  <option>سێ مانگی ڕابردوو</option>
                  <option>ئەمساڵ</option>
                  <option>دیاریکردنی مەودایەک...</option>
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                  <label className="block text-[10px] font-bold text-gray-500 mb-1 uppercase">لە</label>
                  <input type="date" className="w-full bg-slate-900 border border-slate-700 rounded-xl p-2 text-white text-sm" />
                </div>
                 <div>
                  <label className="block text-[10px] font-bold text-gray-500 mb-1 uppercase">بۆ</label>
                  <input type="date" className="w-full bg-slate-900 border border-slate-700 rounded-xl p-2 text-white text-sm" />
                </div>
              </div>
            </div>

            <div className="bg-slate-900/50 p-4 rounded-xl space-y-3">
              <label className="flex items-center text-sm text-gray-300 cursor-pointer">
                <input type="checkbox" defaultChecked className="ml-3 w-5 h-5 rounded border-slate-600 text-amber-500 bg-slate-950" />
