              </label>
              <label className="flex items-center text-sm text-gray-300 cursor-pointer">
                <input type="checkbox" className="ml-3 w-5 h-5 rounded border-slate-600 text-amber-500 bg-slate-950" />
                ناردنی خۆکار بۆ ئیمەیڵی موکیل
              </label>
            </div>

            <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center transition-all shadow-lg ${isGenerating ? 'bg-slate-700 text-gray-500' : 'bg-amber-500 text-slate-900 hover:bg-amber-400 active:scale-95 shadow-amber-500/20'}`}
            >
              {isGenerating ? (
                <span className="flex items-center gap-2">
                   <RefreshCwIcon className="w-5 h-5 animate-spin" />
                   ئامادەکردن...
                </span>
              ) : 'دروستکردنی ڕاپۆرت'}
            </button>
          </div>
        </div>

        {/* Status/Preview Section */}
        <div className="lg:col-span-7 flex flex-col">
            <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-700 border-dashed flex-1 flex flex-col items-center justify-center text-center shadow-inner relative overflow-hidden">
                {!isGenerating && !isFinished && (
                    <div className="animate-in fade-in duration-700">
                        <ChartBarIcon className="w-24 h-24 text-slate-700 mb-6 mx-auto" />
                        <h3 className="text-xl font-bold text-gray-400 mb-2">ڕاپۆرت ئامادە نییە</h3>
                        <p className="text-gray-500 max-w-xs mx-auto">فلتەرەکان هەڵبژێرە و کلیک لە "دروستکردن" بکە بۆ نمایشکردنی داتاکان.</p>
                    </div>
                )}

                {isGenerating && (
                    <div className="w-full max-w-sm space-y-6">
                        <div className="relative h-4 bg-slate-900 rounded-full overflow-hidden shadow-inner">
                            <div className="h-full bg-gradient-to-r from-amber-600 to-amber-400 transition-all duration-300" style={{ width: `${progress}%` }}></div>
                        </div>
                        <div>
                            <p className="text-2xl font-black text-white">{progress}%</p>
                            <p className="text-sm text-amber-500 font-bold mt-1">ئامادەکردنی داتا و پۆلینکردنی دارایی...</p>
                        </div>
                    </div>
                )}

                {isFinished && (
                    <div className="animate-in fade-in zoom-in duration-500">
                        <div className="w-24 h-24 bg-green-500/20 rounded-full flex items-center justify-center mb-6 mx-auto border border-green-500/30">
                            <CheckCircleIcon className="w-14 h-14 text-green-500" />
                        </div>
                        <h3 className="text-3xl font-black text-white mb-3 tracking-tight">ڕاپۆرتەکە ئامادەیە!</h3>
                        <p className="text-gray-400 mb-10 max-w-sm font-medium">پەڕەی PDF بە هەموو وردەکارییەکانەوە دروستکرا و ئامادەیە بۆ داونلۆد.</p>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
