                            </button>
                            <button className="flex items-center justify-center bg-white text-slate-950 px-8 py-4 rounded-xl font-black transition-all shadow-xl hover:scale-105 active:scale-95">
                                <DownloadIcon className="w-5 h-5 ml-3" />
                                داونلۆد (PDF)
                            </button>
                        </div>
                    </div>
                )}
            </div>

            <div className="mt-6 p-5 bg-blue-500/5 border border-blue-500/10 rounded-2xl text-blue-400 text-sm flex items-start leading-relaxed">
               <span className="ml-3 text-xl">✨</span>
               <p className="font-medium">ڕاپۆرتەکان پشت بە نوێترین داتاکانی سیستەمەکە دەبەستن. دەتوانیت لۆگۆی تایبەت بە خۆت لە بەشی "ڕێکخستنەکان" زیاد بکەیت بۆ ئەوەی ڕاپۆرتەکان پڕۆفیشناڵتر دەربکەون.</p>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ReportsPage;
